import { Injectable, Injector } from '@angular/core';
import { FormArray, FormControl, FormGroup } from '@angular/forms';
import { BaseClassNG } from '../class/base.class.a.ng';
import { Custom } from '../static/custom';

@Injectable({
  providedIn: 'root',
})
export class FormService extends BaseClassNG {
  _form: FormGroup;
  constructor() {
    super();
    this._form = this._fb.group({});
  }
  _dd_selected(control: string, value: string, form: FormGroup = this._form) {
    return form.value[control] === value;
  }

  _has(fieldName: string, fg: FormGroup = this._form) {
    return fg?.contains(fieldName);
  }

  _hasVal(fieldName: string, fg: FormGroup = this._form) {
    return Custom.emptyCheck(this._getVal(fieldName, fg));
  }

  _hasGroup(groupName: string, fieldName: string) {
    const group = this._form?.get(groupName) as FormGroup;
    return group?.contains(fieldName);
  }

  _getVal(control: string, group: FormGroup = this._form) {
    return group?.get(control)?.value;
  }

  _checkBoxChecked(val, fieldname) {
    const selectedArray: FormArray = this._form.get(fieldname) as FormArray;
    if (val.target.checked) {
      selectedArray.push(new FormControl(val.target.value));
    } else {
      let i = 0;
      selectedArray.controls.forEach((ctrl: FormControl) => {
        if (ctrl.value == val.target.value) {
          selectedArray.removeAt(i);
          return;
        }
        i++;
      });
    }
    console.log(selectedArray);
  }
}
