import { ChangeDetectorRef, Injectable } from "@angular/core";
import { Subject } from "rxjs";
import { AppInjector } from "../static/AppInjector";


@Injectable({ providedIn: 'root' })
export class TemplateService {
  public title: string = '';
  public layer: string[] = [''];

  public linkCreate: string = '';
  public linkList: string = '';

  public ActionFormSave = () => {console.log('ActionFormSave')};
  public ActionFormCancel = () => {console.log('ActionFormCancel')};
  public ActionFormReset = () => {console.log('ActionFormReset')};

  public ActionListPrint = () => {console.log('ActionListPrint')};
  public ActionListEdit = (id: any) => {console.log('ActionListEdit')};
  public ActionListStatus = (id: any) => {console.log('ActionListStatus')};
  public ActionListDelete = (id: any) => {console.log('ActionListDelete')};
  public ActionListReset = () => {console.log('ActionListReset')};
  public ActionListRefresh = () => {console.log('ActionListRefresh')};
  public ActionListPaginate : any;

  public DATA = new Subject<any>();
  constructor() {
    this.DATA.subscribe({
      next: (data) => {
        this.title = data?.title || '';
        this.layer = data?.layer || ['Module', 'Submodule', 'Page'];

        this.linkCreate = data?.linkCreate || '';
        this.linkList = data?.linkList || '';
      }
    })
  }
}
export const Btn: IBtn = {
  label: 'Action Label',
  icon: 'icon',
  action: () => {
    console.log(this, 'Triggered');
  }
};
export interface IBtn {
  label: string;
  icon: string;
  action: () => void;
}
