import { Component, OnDestroy } from '@angular/core';
import { PartialSubmit } from '../interface/common/partial-submit';
import { BaseClassFuncs } from './base.class.c.funcs';
import { LB } from './build/builder.list';
@Component({ template: '' })
export abstract class BaseClassTemplate extends BaseClassFuncs implements OnDestroy {
  public lb: LB = null;
  // Services Injection
  constructor() {
    super();
    this.resetProperties();
    this.DATA = this._activeRoute.snapshot.data;
    this._id = this.getQuery('id');
    this._template.DATA.next({...this.DATA, CLASS: this.constructor.name});
  }
  // HTTPService (CREATE UPDATE)
  // # SOLID (Open-closed Principle)
  // Objects or entities should be open for extension, but closed for modification.
  /**
   * @see {@link PartialSubmit}
   * @param {param} HttpServiceParam @see {@link HttpServiceParam}
   * @returns boolean | void
   */
  public _onSubmit(ps: PartialSubmit = this._fss.defaultBehaviour): boolean | void {
    ps.defaultHttpParam = this.param;
    ps._id = this._id;
    return this._fss._onSubmit(ps);
  }
  override ngOnDestroy(): void {
    super.ngOnDestroy();
    this._css.looseControlState.forEach((x) => {
      // this._css._ddOneTimeLoad[x] = undefined;
      this._css.loading = this._css.loading.slice(
        this._css.loading.indexOf(x),
        1
      );
    });
  }
}
