import { ChangeDetectorRef, inject } from '@angular/core';
import { FormBuilder } from '@angular/forms';
import { MatDialog } from '@angular/material/dialog';
import { ActivatedRoute, Router } from '@angular/router';
import { CookieService } from 'ngx-cookie-service';
import { DatePipe, Location } from '@angular/common';
import { TranslateService } from '@ngx-translate/core';
import { ToastrService } from 'ngx-toastr';
import { MatSnackBar } from '@angular/material/snack-bar';
import { AppInjector } from '../static/AppInjector';
import { LocalStorageService } from '../service';

// # 1 SOLID PRINCIPLE (Single Responsibility Principle)
// 1. Single responsibility principle: a class should have one, and only one, reason to change;
// 2. When you only want to Inject a Service
export abstract class BaseClassNG {
  // Angular Services
  public _activeRoute = inject(ActivatedRoute);
  public _router = inject(Router);
  public _dialog = inject(MatDialog);
  public _fb = inject(FormBuilder);
  public _location = inject(Location);
  public _cookie = inject(CookieService);
  public _translate = inject(TranslateService);
  public _toastr = inject(ToastrService);
  public _datePipe = inject(DatePipe);
  public _snackBar = inject(MatSnackBar);
  public _storage = inject(LocalStorageService);
  public _cdr: ChangeDetectorRef;
  constructor() {
    // this._datePipe = AppInjector.get(DatePipe);
  }
}
