import { Component, inject, Injector } from '@angular/core';
import { IMG_URL } from '../constant/image';
import { URLz } from '../enums/url.enum';
import { HttpServiceParam } from '../interface/common/http-service-param';
import { Subscription } from 'rxjs';
import { URL_ACTION } from '../enums/action.enum';
import {
  HTTPService,
  FormService,
  ValidatorService,
  FormSubmitService,
  StateService,
  ControlStateService,
  SwalService,
} from '../service';
import { BaseClassNG } from './base.class.a.ng';
import { UtilService } from '../service/srvc.e.util';
import { TemplateService } from '../service/srvc.template';
// In Base Class append all the properties / methods with _ (underscore)

// # 1 SOLID PRINCIPLE (Single Responsibility Principle)
// 1. Single responsibility principle: a class should have one, and only one, reason to change;
// 2. When you only want to Inject a Service
@Component({ template: '' })
export abstract class BaseClassProp extends BaseClassNG {
  public _http = inject(HTTPService);
  public _fs = inject(FormService);
  public _vs = inject(ValidatorService);
  public _fss = inject(FormSubmitService);
  public _ss = inject(StateService);
  public _css = inject(ControlStateService);
  public _swl = inject(SwalService);
  public _util = inject(UtilService);
  public _template = inject(TemplateService);

  // Enum Global Property for HTML Template
  public URLz = URLz; // For Template
  public IMG_URL = IMG_URL; // For Template
  public URL_ACTION = URL_ACTION; // For Template (Route Permission)
  public param: HttpServiceParam = {}; // Override this Property for Default Behaviour of HTTP Request
  public DATA: any = {}; // Route Snapshot Data

  // Guard Related Properties
  public _id: string;
  public _isExist: boolean;
  public subscriptionArray: Subscription[] = [];
  constructor() {
    super();
  }
  // Future Reference for using ngOnChanges
  // ngOnChanges(changes: SimpleChanges) {
  //   for (const propName in changes) {
  //     if (changes.hasOwnProperty(propName)) {
  //       switch (propName) {
  //         case 'myFirstInputParameter': {
  //           this.doSomething(change.currentValue)
  //         }
  //       }
  //     }
  //   }
  // }
}
