import { Component, Input, OnInit } from '@angular/core';
import { FormControl } from '@angular/forms';
import { BaseClassFuncs } from 'src/app/core/class';

@Component({
  selector: 'aam-zmat-form-field',
  templateUrl: './zmat-form-field.component.html',
  styleUrls: ['./zmat-form-field.component.scss']
})
export class ZMatFormFieldComponent extends BaseClassFuncs implements OnInit {
  @Input() control: FormControl | null = null;
  @Input() lbl: string = '';
  errMsg: string = '';

  ngOnInit(): void {
    if(this.control) {
      this.statusChangesSubscription();
    }
  }
  statusChangesSubscription() {
    const subs = this.control?.statusChanges?.subscribe(() => {
      this.errMsg = this._vs.handleRequired(this?.control);
    });
    this.subscriptionArray.push(subs);
  }
}
